from django.shortcuts import render, redirect
from django.views import View
from django.contrib.auth import authenticate, login, logout
from django.contrib.auth.models import User
from django.contrib.auth.mixins import LoginRequiredMixin
from django.contrib import messages
from django.views.generic import TemplateView
from .forms import RegistroForm, LoginForm
from .models import ClienteProfile

class RegisterView(View):
    def get(self, request):
        form = RegistroForm()
        return render(request, 'accounts/register.html', {'form': form})

    def post(self, request):
        form = RegistroForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data['email']
            password = form.cleaned_data['password']

            user = User.objects.create_user(username=email, email=email, password=password)
            ClienteProfile.objects.create(usuario=user)

            user = authenticate(username=email, password=password)
            login(request, user)
            messages.success(request, 'Registro exitoso. Bienvenido a Hundidos.')
            return redirect('/')

        return render(request, 'accounts/register.html', {'form': form})

class LoginView(View):
    def get(self, request):
        form = LoginForm()
        return render(request, 'accounts/login.html', {'form': form})

    def post(self, request):
        form = LoginForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data['email']
            password = form.cleaned_data['password']

            user = authenticate(username=email, password=password)
            if user is not None:
                login(request, user)
                messages.success(request, f'Bienvenido, {email}.')
                return redirect('/')
            else:
                messages.error(request, 'Correo o contraseña incorrectos.')

        return render(request, 'accounts/login.html', {'form': form})

class LogoutView(LoginRequiredMixin, View):
    def post(self, request):
        logout(request)
        messages.success(request, 'Has cerrado sesión correctamente.')
        return redirect('/')

class ProfileView(LoginRequiredMixin, TemplateView):
    template_name = 'accounts/profile.html'
    login_url = 'accounts:login'

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['user'] = self.request.user
        try:
            context['profile'] = self.request.user.cliente_profile
        except:
            context['profile'] = None
        return context

from django.shortcuts import render, get_object_or_404
from django.views.generic import ListView, DetailView
from django.db.models import Q
from .models import Barco, Categoria, Puerto, Fabricante

class BarcoListView(ListView):
    model = Barco
    template_name = 'catalog/list.html'
    context_object_name = 'barcos'
    paginate_by = 12

    def get_queryset(self):
        queryset = Barco.objects.all()

        search = self.request.GET.get('search')
        if search:
            queryset = queryset.filter(
                Q(nombre__icontains=search) | Q(descripcion__icontains=search)
            )

        categoria = self.request.GET.get('categoria')
        if categoria:
            queryset = queryset.filter(categoria_id=categoria)

        puerto = self.request.GET.get('puerto')
        if puerto:
            queryset = queryset.filter(puerto_id=puerto)

        fabricante = self.request.GET.get('fabricante')
        if fabricante:
            queryset = queryset.filter(fabricante_id=fabricante)

        precio_min = self.request.GET.get('precio_min')
        if precio_min:
            try:
                queryset = queryset.filter(precio_dia__gte=float(precio_min))
            except:
                pass

        precio_max = self.request.GET.get('precio_max')
        if precio_max:
            try:
                queryset = queryset.filter(precio_dia__lte=float(precio_max))
            except:
                pass

        capacidad_min = self.request.GET.get('capacidad_min')
        if capacidad_min:
            try:
                queryset = queryset.filter(capacidad__gte=int(capacidad_min))
            except:
                pass

        return queryset.order_by('-created_at')

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['categorias'] = Categoria.objects.all()
        context['puertos'] = Puerto.objects.all()
        context['fabricantes'] = Fabricante.objects.all()
        context['search'] = self.request.GET.get('search', '')
        context['categoria_selected'] = self.request.GET.get('categoria', '')
        context['puerto_selected'] = self.request.GET.get('puerto', '')
        context['fabricante_selected'] = self.request.GET.get('fabricante', '')
        return context

class BarcoDetailView(DetailView):
    model = Barco
    template_name = 'catalog/detail.html'
    context_object_name = 'barco'
    pk_url_kwarg = 'id'

from decimal import Decimal

class CartService:
    CART_SESSION_KEY = 'cart'

    @staticmethod
    def get_cart(request):
        if CartService.CART_SESSION_KEY not in request.session:
            request.session[CartService.CART_SESSION_KEY] = {}
        return request.session[CartService.CART_SESSION_KEY]

    @staticmethod
    def add_to_cart(request, barco_id, cantidad):
        cart = CartService.get_cart(request)
        barco_id_str = str(barco_id)

        if barco_id_str in cart:
            cart[barco_id_str]['cantidad'] += cantidad
        else:
            from catalog.models import Barco
            barco = Barco.objects.get(id=barco_id)
            cart[barco_id_str] = {
                'nombre': barco.nombre,
                'precio_dia': str(barco.precio_dia),
                'cantidad': cantidad,
                'barco_id': barco_id
            }

        request.session[CartService.CART_SESSION_KEY] = cart
        request.session.modified = True

    @staticmethod
    def update_cart(request, barco_id, cantidad):
        cart = CartService.get_cart(request)
        barco_id_str = str(barco_id)

        if barco_id_str in cart:
            if cantidad <= 0:
                del cart[barco_id_str]
            else:
                cart[barco_id_str]['cantidad'] = cantidad

        request.session[CartService.CART_SESSION_KEY] = cart
        request.session.modified = True

    @staticmethod
    def clear_cart(request):
        request.session[CartService.CART_SESSION_KEY] = {}
        request.session.modified = True

    @staticmethod
    def get_cart_total(request):
        cart = CartService.get_cart(request)
        total = Decimal('0')
        for item in cart.values():
            total += Decimal(item['precio_dia']) * item['cantidad']
        return total

    @staticmethod
    def get_cart_count(request):
        cart = CartService.get_cart(request)
        count = 0
        for item in cart.values():
            count += item['cantidad']
        return count

from django.shortcuts import render, redirect
from django.views import View
from django.contrib import messages
from django.views.generic import TemplateView
from .services import CartService
from catalog.models import Barco

class CartView(TemplateView):
    template_name = 'cart/view.html'

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        cart = CartService.get_cart(self.request)

        cart_items = []
        for barco_id_str, item in cart.items():
            try:
                barco = Barco.objects.get(id=int(barco_id_str))
                item['barco'] = barco
                cart_items.append(item)
            except Barco.DoesNotExist:
                pass

        context['cart_items'] = cart_items
        context['cart_total'] = CartService.get_cart_total(self.request)
        context['cart_count'] = CartService.get_cart_count(self.request)
        return context

class AddToCartView(View):
    def post(self, request):
        barco_id = request.POST.get('barco_id')
        cantidad = request.POST.get('cantidad', 1)

        try:
            barco_id = int(barco_id)
            cantidad = int(cantidad)

            if cantidad <= 0:
                messages.error(request, 'La cantidad debe ser mayor a 0.')
                return redirect('catalog:barco_detail', id=barco_id)

            barco = Barco.objects.get(id=barco_id)
            CartService.add_to_cart(request, barco_id, cantidad)
            messages.success(request, f'{barco.nombre} añadido a la cesta.')
        except (ValueError, Barco.DoesNotExist):
            messages.error(request, 'Error al añadir el barco a la cesta.')

        return redirect('cart:view')

class UpdateCartView(View):
    def post(self, request):
        barco_id = request.POST.get('barco_id')
        cantidad = request.POST.get('cantidad', 0)

        try:
            barco_id = int(barco_id)
            cantidad = int(cantidad)
            CartService.update_cart(request, barco_id, cantidad)
            messages.success(request, 'Cesta actualizada.')
        except ValueError:
            messages.error(request, 'Error al actualizar la cesta.')

        return redirect('cart:view')

class ClearCartView(View):
    def post(self, request):
        CartService.clear_cart(request)
        messages.success(request, 'Cesta vaciada.')
        return redirect('cart:view')

