{% block title %}Registro - Hundidos{% endblock %}

{% block content %}
<div class="container" style="max-width: 500px; margin: 40px auto;">
    <h2>Registro de Cliente</h2>
    <form method="post" novalidate>
        {% csrf_token %}

        {% if form.non_field_errors %}
            <div style="color: red; margin-bottom: 10px;">
                {% for error in form.non_field_errors %}
                    <p>{{ error }}</p>
                {% endfor %}
            </div>
        {% endif %}

        <div style="margin-bottom: 15px;">
            <label for="{{ form.email.id_for_label }}">{{ form.email.label }}</label>
            {{ form.email }}
            {% if form.email.errors %}
                <div style="color: red; font-size: 12px;">
                    {% for error in form.email.errors %}
                        <p>{{ error }}</p>
                    {% endfor %}
                </div>
            {% endif %}
        </div>

        <div style="margin-bottom: 15px;">
            <label for="{{ form.password.id_for_label }}">{{ form.password.label }}</label>
            {{ form.password }}
            {% if form.password.errors %}
                <div style="color: red; font-size: 12px;">
                    {% for error in form.password.errors %}
                        <p>{{ error }}</p>
                    {% endfor %}
                </div>
            {% endif %}
        </div>

        <div style="margin-bottom: 15px;">
            <label for="{{ form.password_confirm.id_for_label }}">{{ form.password_confirm.label }}</label>
            {{ form.password_confirm }}
            {% if form.password_confirm.errors %}
                <div style="color: red; font-size: 12px;">
                    {% for error in form.password_confirm.errors %}
                        <p>{{ error }}</p>
                    {% endfor %}
                </div>
            {% endif %}
        </div>

        <button type="submit" style="background-color: #003d82; color: white; padding: 10px 20px; border: none; border-radius: 4px; cursor: pointer; width: 100%;">Registrarse</button>
    </form>

    <p style="margin-top: 20px; text-align: center;">
        ¿Ya tienes cuenta? <a href="{% url 'accounts:login' %}">Inicia sesión aquí</a>
    </p>
</div>
{% endblock %}

